function parseAudiencia(v: string): number | null {
  if (!v || v === "n/a") return null;
  return parseInt(v.replace(/\./g, ""), 10);
}

function parsePNT(v: string): number | null {
  if (!v || v === "n/a") return null;
  return parseFloat(v.replace(",", "."));
}

